import{_ as a,o as r,c as e,ae as o}from"./chunks/framework.Bs0ChzWn.js";const p=JSON.parse('{"title":"帮助","description":"","frontmatter":{},"headers":[],"relativePath":"pages/about/index.md","filePath":"pages/about/index.md"}'),n={name:"pages/about/index.md"};function d(l,t,s,i,h,c){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="帮助" tabindex="-1">帮助 <a class="header-anchor" href="#帮助" aria-label="Permalink to &quot;帮助&quot;">​</a></h1><p>本页为每日预测功能的使用说明。</p><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>本项目通过 GitHub Actions 实现<strong>每日自动化 CI 流程</strong>：每晚 10 点触发，自动从 <a href="https://github.com/chenditc/investment_data" target="_blank" rel="noreferrer">chenditc/investment_data</a> 拉取最新 A 股数据，完成模型训练与选股预测。</p><h2 id="训练流程" tabindex="-1">训练流程 <a class="header-anchor" href="#训练流程" aria-label="Permalink to &quot;训练流程&quot;">​</a></h2><ol><li><strong>数据获取</strong>：自动拉取最新 A 股行情数据</li><li><strong>模型训练</strong>：采用仅需 CPU 的模型（XGBoost、LightGBM、DoubleEnsemble、Linear），分别用过去 1～5 年历史数据训练，共得到 20 个模型</li><li><strong>模型筛选</strong>：按 IC、ICIR、Rank IC、Rank ICIR 等指标筛选表现较好的模型</li><li><strong>预测输出</strong>：多模型同时预测，取平均分数作为最终结果</li></ol><h2 id="分数含义" tabindex="-1">分数含义 <a class="header-anchor" href="#分数含义" aria-label="Permalink to &quot;分数含义&quot;">​</a></h2><p><strong>预测分数（score）</strong>：基于 T 日收盘数据，预测「T+1 日收盘买入、T+2 日收盘卖出」的期望收益率。</p><blockquote><p>注：该收益率为理论值，未考虑 A 股 10% 涨跌停板限制。<br><strong>score</strong> 与 <strong>label</strong> 为同一概念：预测值为 score，真实收益率为 label。</p></blockquote><h2 id="数据表格说明" tabindex="-1">数据表格说明 <a class="header-anchor" href="#数据表格说明" aria-label="Permalink to &quot;数据表格说明&quot;">​</a></h2><p><strong>查看建议</strong>：按文件名中的日期优先查看最新表格，推荐先看 <code>xxx_ret</code> 汇总表。</p><h3 id="表格列说明" tabindex="-1">表格列说明 <a class="header-anchor" href="#表格列说明" aria-label="Permalink to &quot;表格列说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列名</th><th>含义</th></tr></thead><tbody><tr><td>instrument</td><td>股票代码</td></tr><tr><td>avg_score</td><td>多模型预测的平均分数，即期望收益率</td></tr><tr><td>pos_ratio</td><td>预测为正收益的模型占比。如 1 表示全部预测正收益，0.875 表示 8 个模型中有 7 个预测正收益</td></tr><tr><td>real_label</td><td>真实收益率。预测未来时为 nan；若为历史日期，可得到真实值用于回测对比</td></tr><tr><td>datetime</td><td>预测日期。如 2026-02-11 表示：基于 02-11 收盘数据预测，02-12 收盘买入、02-13 收盘卖出的期望收益率</td></tr></tbody></table><h3 id="文件类型" tabindex="-1">文件类型 <a class="header-anchor" href="#文件类型" aria-label="Permalink to &quot;文件类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文件</th><th>说明</th></tr></thead><tbody><tr><td>total.csv</td><td>模型预测原始数据，含各模型 score</td></tr><tr><td>xxx_ret</td><td>多模型平均后的汇总结果</td></tr><tr><td>xxx_filter_ret</td><td>经规则过滤后的汇总结果</td></tr></tbody></table><p><strong>filter 的简单规则</strong>（稳健性过滤）：</p><ul><li><strong>波动率（STD）</strong>：STD5、STD20、STD60 均 &lt; 0.10，且 STD60 &lt; 0.05、STD5 &lt; 0.06；短期波动 STD5 不超过长期 STD60 的 2 倍</li><li><strong>动量（ROC）</strong>：ROC10、ROC20、ROC60 均 &gt; 0.80，且 ROC20 &lt; 1.30，剔除波动过大或动量过猛的标的</li></ul><h3 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h3><p><strong>Q：为什么表格里有时没有股票中文名称？</strong></p><p>A：股票名称来自外部数据接口（如沪深交易所、东方财富等）。GitHub Actions 运行在海外服务器上，访问国内数据源时易出现超时、限流或返回异常，导致名称拉取失败。此时表格仍会保留股票代码，不影响预测分数等核心数据的查看。</p><p><strong>Q：为什么每次参与预测的模型数量不同？</strong></p><p>A：系统会对模型按 IC、ICIR 等指标进行筛选，过滤条件较严格。新训练的模型若整体表现不佳，可能全部被过滤，导致当日无模型参与预测。若发现此类情况，我会及时调整过滤阈值，确保至少有一个模型可用。</p><p><strong>Q：为什么有时一天预测了两次？</strong></p><p>A：调试或验证时会手动触发 GitHub Action，执行完成后会按流程自动同步到页面，因此可能出现同一天多次更新的情况。</p>',24)])])}const g=a(n,[["render",d]]);export{p as __pageData,g as default};
